import React, { useEffect, useState } from 'react';
import Toast from '../components/Toast';
import api from '../utils/api';

const SC: any = { pending:'#f59e0b', approved:'#10b981', rejected:'#ef4444' };

export default function BorrowRequests() {
  const [requests, setRequests] = useState<any[]>([]);
  const [loading, setLoading]   = useState(true);
  const [filter, setFilter]     = useState('pending');
  const [toast, setToast]       = useState<any>(null);
  const [rejectModal, setRejectModal] = useState<any>(null);
  const [rejectReason, setRejectReason] = useState('');
  const [approveModal, setApproveModal] = useState<any>(null);
  const [dueDate, setDueDate]   = useState('');

  const load = (status = filter) => {
    setLoading(true);
    api.get('/borrows/requests', { params:{ status } })
      .then(r=>{ setRequests(r.data.data||[]); setLoading(false); })
      .catch(()=>setLoading(false));
  };

  useEffect(()=>{ load(filter); }, [filter]);

  const openApprove = (req:any) => {
    const d=new Date(); d.setDate(d.getDate()+14);
    setDueDate(d.toISOString().split('T')[0]);
    setApproveModal(req);
  };

  const approve = async () => {
    try {
      await api.put(`/borrows/requests/${approveModal.id}/approve`,{due_date:dueDate});
      setToast({message:'Request approved! Book issued.',type:'success'});
      setApproveModal(null); load();
    } catch(e:any){ setToast({message:e.response?.data?.message||'Error',type:'error'}); }
  };

  const reject = async () => {
    try {
      await api.put(`/borrows/requests/${rejectModal.id}/reject`,{reject_reason:rejectReason});
      setToast({message:'Request rejected',type:'info'});
      setRejectModal(null); setRejectReason(''); load();
    } catch { setToast({message:'Error occurred',type:'error'}); }
  };

  return (
    <div className="page-enter" style={{ padding:'32px 36px', width:'100%' }}>
      {toast && <Toast message={toast.message} type={toast.type} onClose={()=>setToast(null)} />}

      <div style={{ marginBottom:28 }}>
        <h1 style={{ fontFamily:"'Playfair Display',serif",fontSize:32,fontWeight:700,color:'var(--text)' }}>Borrow Requests</h1>
        <p style={{ color:'var(--text-muted)',fontSize:14,marginTop:4 }}>Review and approve member requests</p>
      </div>

      {/* Tabs */}
      <div style={{ display:'flex',gap:8,marginBottom:20 }}>
        {[['pending','Pending'],['approved','Approved'],['rejected','Rejected']].map(([val,label])=>(
          <button key={val} onClick={()=>setFilter(val)}
            style={{ padding:'9px 20px',background:filter===val?'#c9a84c':'var(--bg2)',color:filter===val?'#1a1a2e':'var(--text-dim)',border:filter===val?'none':'1px solid var(--border)',borderRadius:10,fontSize:13,fontWeight:filter===val?700:500,cursor:'pointer',fontFamily:'inherit',transition:'all .2s' }}>
            {label}
          </button>
        ))}
      </div>

      {loading ? (
        <div style={{ display:'flex',justifyContent:'center',padding:80 }}>
          <div style={{ width:32,height:32,border:'3px solid #c9a84c',borderTopColor:'transparent',borderRadius:'50%',animation:'spin 1s linear infinite' }}/>
        </div>
      ) : requests.length ? (
        <div style={{ display:'grid',gap:14 }}>
          {requests.map(req=>(
            <div key={req.id} style={{ background:'var(--bg2)',border:'1px solid var(--border)',borderRadius:16,padding:20 }}>
              <div style={{ display:'flex',gap:16,flexWrap:'wrap' }}>

                {/* Book Info */}
                <div style={{ flex:1,minWidth:200 }}>
                  <div style={{ fontSize:11,fontWeight:700,color:'var(--text-muted)',textTransform:'uppercase',marginBottom:6,letterSpacing:'1px' }}>Book</div>
                  <div style={{ fontSize:15,fontWeight:700,color:'var(--text)',marginBottom:2 }}>{req.title}</div>
                  <div style={{ fontSize:12,color:'var(--text-muted)',marginBottom:10 }}>{req.author}</div>
                  <span style={{ fontSize:11,fontWeight:700,padding:'3px 11px',borderRadius:99,background:req.available_copies>0?'rgba(16,185,129,0.15)':'rgba(239,68,68,0.12)',color:req.available_copies>0?'#10b981':'#ef4444' }}>
                    {req.available_copies} copies available
                  </span>
                </div>

                {/* Member Info */}
                <div style={{ flex:1,minWidth:200,background:'var(--bg3)',border:'1px solid var(--border)',borderRadius:12,padding:14 }}>
                  <div style={{ fontSize:11,fontWeight:700,color:'var(--text-muted)',textTransform:'uppercase',marginBottom:8,letterSpacing:'1px' }}>Member Info</div>
                  <div style={{ display:'grid',gridTemplateColumns:'1fr 1fr',gap:8 }}>
                    {[['Name',req.member_name],['ID',req.member_code],['Type',req.account_type],['Department',req.department||'—'],['Batch',req.batch||'—'],['Mobile',req.mobile||'—']].map(([label,value])=>(
                      <div key={label}>
                        <div style={{ fontSize:10,color:'var(--text-muted)',fontWeight:700,textTransform:'uppercase',letterSpacing:'.5px' }}>{label}</div>
                        <div style={{ fontSize:12,fontWeight:600,color:'var(--text)',marginTop:1 }}>{value}</div>
                      </div>
                    ))}
                  </div>
                </div>

                {/* Actions */}
                <div style={{ display:'flex',flexDirection:'column',justifyContent:'space-between',alignItems:'flex-end',minWidth:140 }}>
                  <div style={{ textAlign:'right' }}>
                    <span style={{ fontSize:11,fontWeight:700,padding:'4px 12px',borderRadius:99,background:(SC[req.status]||'#6b7280')+'22',color:SC[req.status]||'#6b7280',textTransform:'capitalize' }}>
                      {req.status}
                    </span>
                    <div style={{ fontSize:11,color:'var(--text-muted)',marginTop:6 }}>
                      {new Date(req.request_date).toLocaleDateString('en-GB')}
                    </div>
                    {req.reviewed_by_name && <div style={{ fontSize:11,color:'var(--text-muted)',marginTop:4 }}>By: {req.reviewed_by_name}</div>}
                    {req.reject_reason && <div style={{ fontSize:11,color:'#ef4444',marginTop:4,maxWidth:160 }}>"{req.reject_reason}"</div>}
                  </div>
                  {req.status==='pending' && (
                    <div style={{ display:'flex',gap:8,marginTop:12 }}>
                      <button onClick={()=>openApprove(req)} style={{ padding:'8px 16px',background:'rgba(16,185,129,0.15)',color:'#10b981',border:'1px solid rgba(16,185,129,0.25)',borderRadius:9,fontSize:13,fontWeight:700,cursor:'pointer',fontFamily:'inherit' }}>Approve</button>
                      <button onClick={()=>{setRejectModal(req);setRejectReason('');}} style={{ padding:'8px 16px',background:'rgba(239,68,68,0.12)',color:'#ef4444',border:'1px solid rgba(239,68,68,0.2)',borderRadius:9,fontSize:13,fontWeight:600,cursor:'pointer',fontFamily:'inherit' }}>Reject</button>
                    </div>
                  )}
                </div>
              </div>
            </div>
          ))}
        </div>
      ) : (
        <div style={{ textAlign:'center',padding:80 }}>
          <div style={{ fontSize:14,color:'var(--text-muted)',fontStyle:'italic' }}>No {filter} requests</div>
        </div>
      )}

      {/* Approve Modal */}
      {approveModal && (
        <div style={{ position:'fixed',inset:0,background:'rgba(0,0,0,0.75)',backdropFilter:'blur(6px)',zIndex:1000,display:'flex',alignItems:'center',justifyContent:'center',padding:20 }}>
          <div style={{ background:'var(--bg2)',border:'1px solid var(--border)',borderRadius:20,padding:28,width:'100%',maxWidth:400 }}>
            <h2 style={{ fontFamily:"'Playfair Display',serif",fontSize:20,fontWeight:700,marginBottom:6,color:'var(--text)' }}>Approve Request</h2>
            <p style={{ fontSize:13,color:'var(--text-muted)',marginBottom:20 }}>
              Issuing <strong style={{ color:'var(--text)' }}>{approveModal.title}</strong> to <strong style={{ color:'var(--text)' }}>{approveModal.member_name}</strong>
            </p>
            <div style={{ marginBottom:20 }}>
              <label style={{ display:'block',fontSize:12,fontWeight:600,color:'var(--text-muted)',marginBottom:6 }}>Due Date</label>
              <input className="field" type="date" value={dueDate} onChange={e=>setDueDate(e.target.value)} />
            </div>
            <div style={{ display:'flex',gap:10 }}>
              <button onClick={()=>setApproveModal(null)} className="btn-ghost" style={{ flex:1 }}>Cancel</button>
              <button onClick={approve} style={{ flex:1,padding:'10px',background:'#10b981',color:'#fff',border:'none',borderRadius:10,cursor:'pointer',fontFamily:'inherit',fontSize:13,fontWeight:700 }}>Confirm Approve</button>
            </div>
          </div>
        </div>
      )}

      {/* Reject Modal */}
      {rejectModal && (
        <div style={{ position:'fixed',inset:0,background:'rgba(0,0,0,0.75)',backdropFilter:'blur(6px)',zIndex:1000,display:'flex',alignItems:'center',justifyContent:'center',padding:20 }}>
          <div style={{ background:'var(--bg2)',border:'1px solid var(--border)',borderRadius:20,padding:28,width:'100%',maxWidth:400 }}>
            <h2 style={{ fontFamily:"'Playfair Display',serif",fontSize:20,fontWeight:700,marginBottom:6,color:'var(--text)' }}>Reject Request</h2>
            <p style={{ fontSize:13,color:'var(--text-muted)',marginBottom:20 }}>
              Rejecting <strong style={{ color:'var(--text)' }}>{rejectModal.title}</strong> from <strong style={{ color:'var(--text)' }}>{rejectModal.member_name}</strong>
            </p>
            <div style={{ marginBottom:20 }}>
              <label style={{ display:'block',fontSize:12,fontWeight:600,color:'var(--text-muted)',marginBottom:6 }}>Reason (optional)</label>
              <textarea className="field" style={{ minHeight:80,resize:'vertical' }} value={rejectReason} onChange={e=>setRejectReason(e.target.value)} placeholder="e.g. Book reserved for another member..." />
            </div>
            <div style={{ display:'flex',gap:10 }}>
              <button onClick={()=>setRejectModal(null)} className="btn-ghost" style={{ flex:1 }}>Cancel</button>
              <button onClick={reject} style={{ flex:1,padding:'10px',background:'#ef4444',color:'#fff',border:'none',borderRadius:10,cursor:'pointer',fontFamily:'inherit',fontSize:13,fontWeight:700 }}>Confirm Reject</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
